template:
const std = @import("std");
const Allocator = std.mem.Allocator;

pub fn slidingWindowMax(allocator: Allocator, arr: []const i32, k: usize) ![]i32 {
    if (arr.len == 0 or k == 0) return try allocator.alloc(i32, 0);

    const result_len = arr.len - k + 1;
    var result = try allocator.alloc(i32, result_len);

    // Deque stores indices - we'll use ArrayList as deque
    var deque: std.ArrayList(usize) = .empty;
    defer deque.deinit(allocator);

    // Process first window
    var i: usize = 0;
    while (i < k) : (i += 1) {
        // Remove elements smaller than current from back
        while (deque.items.len > 0 and [[SLOT back_check]]) {
            _ = [[SLOT pop_call]];
        }
        try deque.append(allocator, i);
    }

    result[0] = [[SLOT window_max]];

    // Process remaining windows
    var result_idx: usize = 1;
    while (i < arr.len) : (i += 1) {
        // Remove indices outside current window from front
        while (deque.items.len > 0 and [[SLOT front_check]]) {
            _ = [[SLOT front_remove]];
        }

        // Remove elements smaller than current from back
        while (deque.items.len > 0 and arr[deque.items[deque.items.len - 1]] <= arr[i]) {
            _ = deque.pop();
        }

        try deque.append(allocator, i);
        result[result_idx] = arr[deque.items[0]];
        result_idx += 1;
    }

    return result;
}
